function _wpDataToBlob(dataURL){
  var parts = dataURL.split(','); var mime=(parts[0].match(/:(.*?);/)||[])[1]||'';
  var bin=(TOP.atob||atob)(parts[1]); var len=bin.length; var arr=new Uint8Array(len);
  for(var i=0;i<len;i++) arr[i]=bin.charCodeAt(i);
  return new (TOP.Blob||Blob)([arr], {type:mime});
}

function _wpResolve(url, cb){
  url = (url||'').trim();
  if(!url){ cb('', null); return; }
  if(/i\.postimg\.cc|i\.postimages\.org/i.test(url) || /\.(png|jpe?g|gif|webp|bmp|mp4|webm|ogg|mov)(\?|#|$)/i.test(url)){ cb(url, null); return; }
  if(/postimg\.cc|postimages\.org/i.test(url)){
    var TIP = '该页面链接受浏览器跨域(CORS)限制，无法自动解析。请在 postimg 图片页右键图片「复制图片地址」，或用「Direct link 直接链接」(i.postimg.cc/...) 再粘贴。';
    if(!TOP.fetch){ cb('', TIP); return; }
    TOP.fetch(url).then(function(r){ return r.text(); }).then(function(t){
      var m = t.match(/property=["']og:image["'][^>]*content=["']([^"']+)["']/i)
           || t.match(/content=["']([^"']+)["'][^>]*property=["']og:image["']/i);
      if(m) cb(m[1], null); else cb('', TIP);
    }).catch(function(){ cb('', TIP); });
  } else { cb(url, null); }
}

